'use strict';

/**
* Return the index of the first truthy element in a single-precision floating-point strided array.
*
* @module @stdlib/blas-ext-base-sindex-of-truthy
*
* @example
* var Float32Array = require( '@stdlib/array-float32' );
* var sindexOfTruthy = require( '@stdlib/blas-ext-base-sindex-of-truthy' );
*
* var x = new Float32Array( [ 0.0, 0.0, 3.0, 0.0, 4.0, 0.0, -1.0, 3.0 ] );
*
* var idx = sindexOfTruthy( x.length, x, 1 );
* // returns 2
*
* @example
* var Float32Array = require( '@stdlib/array-float32' );
* var sindexOfTruthy = require( '@stdlib/blas-ext-base-sindex-of-truthy' );
*
* var x = new Float32Array( [ 0.0, 0.0, 3.0, 0.0, 4.0, 0.0, -1.0, 3.0 ] );
*
* var idx = sindexOfTruthy.ndarray( x.length, x, 1, 0 );
* // returns 2
*/

// MODULES //

var join = require( 'path' ).join;
var tryRequire = require( '@stdlib/utils-try-require' );
var isError = require( '@stdlib/assert-is-error' );
var main = require( './main.js' );


// MAIN //

var sindexOfTruthy;
var tmp = tryRequire( join( __dirname, './native.js' ) );
if ( isError( tmp ) ) {
	sindexOfTruthy = main;
} else {
	sindexOfTruthy = tmp;
}


// EXPORTS //

module.exports = sindexOfTruthy;

// exports: { "ndarray": "sindexOfTruthy.ndarray" }
